// =============================================================
// App.js  —  Vehicle Safety Prediction Frontend  (v3)
// User-facing inputs : distance, time-to-collision, relative_velocity
// Hidden defaults    : axis=0.1, speed=60, steering_angle=5
// After prediction   : graphical gauges + bar chart for sensor values
// =============================================================

import React, { useState } from "react";

const API_BASE = "http://localhost:8000";

// ── Hidden fixed defaults for fields not shown in the form ──
const HIDDEN_DEFAULTS = { axis: 0.1, speed: 60, steering_angle: 5 };

// ── Status theme ─────────────────────────────────────────────
const THEME = {
  safe:    { bg: "#e8f5e9", border: "#43a047", accent: "#2e7d32", text: "#1b5e20", label: "SAFE",    emoji: "✅", gauge: "#43a047" },
  warning: { bg: "#fffde7", border: "#fdd835", accent: "#f9a825", text: "#7c5000", label: "WARNING", emoji: "⚠️",  gauge: "#fdd835" },
  danger:  { bg: "#ffebee", border: "#e53935", accent: "#c62828", text: "#7f0000", label: "DANGER",  emoji: "🚨", gauge: "#e53935" },
};

// ── Gauge ranges for the 3 visible sensors ───────────────────
const SENSOR_META = {
  distance:          { label: "Distance",           unit: "m",   min: 0,   max: 120, safe: [40, 120], warn: [10, 40],  danger: [0, 10]   },
  ttc:               { label: "Time-to-Collision",  unit: "s",   min: 0,   max: 15,  safe: [5, 15],   warn: [2, 5],    danger: [0, 2]    },
  relative_velocity: { label: "Relative Velocity",  unit: "m/s", min: -35, max: 35,  safe: [-5, 5],   warn: [-15, 15], danger: [-35, 35] },
};

// ── Sample presets ────────────────────────────────────────────
const SAMPLES = {
  safe:    { distance: "80",  ttc: "10",  relative_velocity: "1"   },
  warning: { distance: "20",  ttc: "3.5", relative_velocity: "-12" },
  danger:  { distance: "5",   ttc: "0.8", relative_velocity: "-25" },
};

const DEFAULT_FORM = { distance: "", ttc: "", relative_velocity: "" };

// =============================================================
// SVG Arc Gauge Component
// =============================================================
function ArcGauge({ value, min, max, color, label, unit }) {
  const SIZE   = 120;
  const R      = 48;
  const CX     = SIZE / 2;
  const CY     = SIZE / 2 + 10;
  const START  = 210;  // degrees
  const SWEEP  = 120;  // degrees of arc

  const toRad  = (deg) => (deg * Math.PI) / 180;
  const norm   = Math.min(1, Math.max(0, (value - min) / (max - min)));
  const angle  = START + norm * SWEEP;

  const arcX   = (deg) => CX + R * Math.cos(toRad(deg));
  const arcY   = (deg) => CY + R * Math.sin(toRad(deg));

  // Background track arc
  const bgPath = `M ${arcX(START)} ${arcY(START)} A ${R} ${R} 0 0 1 ${arcX(START + SWEEP)} ${arcY(START + SWEEP)}`;
  // Filled arc
  const fgPath = norm > 0
    ? `M ${arcX(START)} ${arcY(START)} A ${R} ${R} 0 ${norm * SWEEP > 180 ? 1 : 0} 1 ${arcX(angle)} ${arcY(angle)}`
    : null;

  return (
    <div style={{ textAlign: "center", flex: 1, minWidth: 120 }}>
      <svg width={SIZE} height={SIZE} viewBox={`0 0 ${SIZE} ${SIZE}`}>
        {/* Track */}
        <path d={bgPath} fill="none" stroke="#e0e0e0" strokeWidth={10} strokeLinecap="round" />
        {/* Value arc */}
        {fgPath && <path d={fgPath} fill="none" stroke={color} strokeWidth={10} strokeLinecap="round" />}
        {/* Needle dot */}
        <circle cx={arcX(angle)} cy={arcY(angle)} r={5} fill={color} />
        {/* Value text */}
        <text x={CX} y={CY + 4} textAnchor="middle" fontSize={16} fontWeight="bold" fill="#1B2B4B">
          {value}
        </text>
        <text x={CX} y={CY + 18} textAnchor="middle" fontSize={9} fill="#888">
          {unit}
        </text>
      </svg>
      <div style={{ fontSize: 12, fontWeight: 600, color: "#444", marginTop: -8 }}>{label}</div>
    </div>
  );
}

// =============================================================
// Horizontal Bar Gauge
// =============================================================
function BarGauge({ value, min, max, color, label, unit }) {
  const norm = Math.min(1, Math.max(0, (value - min) / (max - min)));
  return (
    <div style={{ marginBottom: 14 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
        <span style={{ fontSize: 12, fontWeight: 600, color: "#444" }}>{label}</span>
        <span style={{ fontSize: 12, fontWeight: 700, color: "#1B2B4B" }}>{value} {unit}</span>
      </div>
      <div style={{ background: "#e8ecf4", borderRadius: 6, height: 12, overflow: "hidden" }}>
        <div style={{
          width: `${norm * 100}%`, height: "100%",
          background: color, borderRadius: 6,
          transition: "width 0.6s ease",
        }} />
      </div>
    </div>
  );
}

// =============================================================
// Risk Score Meter (0–100)
// =============================================================
function RiskMeter({ status }) {
  const scores = { safe: 12, warning: 55, danger: 90 };
  const score  = scores[status] || 0;
  const colors = ["#43a047", "#43a047", "#fdd835", "#fdd835", "#e53935", "#e53935"];

  return (
    <div style={{ marginTop: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 6 }}>
        <span style={{ fontSize: 12, fontWeight: 600, color: "#555" }}>Risk Level</span>
        <span style={{ fontSize: 13, fontWeight: 700, color: "#1B2B4B" }}>{score}%</span>
      </div>
      <div style={{ display: "flex", gap: 3, height: 14, borderRadius: 7, overflow: "hidden" }}>
        {colors.map((c, i) => {
          const segStart = i * (100 / colors.length);
          const filled   = score >= segStart + (100 / colors.length);
          const partial  = score > segStart && score < segStart + (100 / colors.length);
          const pct      = partial ? ((score - segStart) / (100 / colors.length)) * 100 : filled ? 100 : 0;
          return (
            <div key={i} style={{ flex: 1, background: "#e0e0e0", borderRadius: 3, overflow: "hidden" }}>
              <div style={{ width: `${pct}%`, height: "100%", background: c, transition: "width 0.7s ease" }} />
            </div>
          );
        })}
      </div>
      <div style={{ display: "flex", justifyContent: "space-between", marginTop: 3 }}>
        <span style={{ fontSize: 10, color: "#43a047" }}>Safe</span>
        <span style={{ fontSize: 10, color: "#fdd835" }}>Warning</span>
        <span style={{ fontSize: 10, color: "#e53935" }}>Danger</span>
      </div>
    </div>
  );
}

// =============================================================
// Main App
// =============================================================
function App() {
  const [form,        setForm]        = useState(DEFAULT_FORM);
  const [result,      setResult]      = useState(null);
  const [submittedForm, setSubmittedForm] = useState(null);
  const [loading,     setLoading]     = useState(false);
  const [error,       setError]       = useState(null);
  const [history,     setHistory]     = useState([]);
  const [showHistory, setShowHistory] = useState(false);
  const [histLoading, setHistLoading] = useState(false);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
    setError(null);
  };

  const loadSample = (type) => {
    setForm(SAMPLES[type]);
    setResult(null);
    setError(null);
    setSubmittedForm(null);
  };

  const handleReset = () => {
    setForm(DEFAULT_FORM);
    setResult(null);
    setError(null);
    setSubmittedForm(null);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setResult(null);
    setError(null);

    // Validate visible fields
    for (const key of ["distance", "ttc", "relative_velocity"]) {
      if (form[key] === "") {
        setError(`Please enter a value for ${SENSOR_META[key].label}.`);
        setLoading(false);
        return;
      }
    }

    // Build full payload — visible + hidden defaults
    const payload = {
      distance:          parseFloat(form.distance),
      ttc:               parseFloat(form.ttc),
      relative_velocity: parseFloat(form.relative_velocity),
      ...HIDDEN_DEFAULTS,
    };

    try {
      const response = await fetch(`${API_BASE}/predict`, {
        method:  "POST",
        headers: { "Content-Type": "application/json" },
        body:    JSON.stringify(payload),
      });
      if (!response.ok) {
        const errData = await response.json();
        throw new Error(errData.detail || "Prediction failed.");
      }
      const data = await response.json();
      setResult(data);
      setSubmittedForm(payload);
      if (showHistory) fetchHistory();
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const fetchHistory = async () => {
    setHistLoading(true);
    try {
      const r = await fetch(`${API_BASE}/history?limit=20`);
      setHistory(await r.json());
    } catch { setHistory([]); }
    finally  { setHistLoading(false); }
  };

  const toggleHistory = () => {
    if (!showHistory) fetchHistory();
    setShowHistory(!showHistory);
  };

  const theme = result ? (THEME[result.predicted_status] || THEME.safe) : null;

  // ── Gauge color per sensor value ────────────────────────────
  const gaugeColor = (key, val) => {
    const m = SENSOR_META[key];
    if (!m) return "#2E5FA3";
    const abs = Math.abs(val);
    const absDanger = Math.abs(m.danger[1]);
    const absWarn   = Math.abs(m.warn[1]);
    if (abs <= absWarn * 0.4) return "#43a047";
    if (abs <= absDanger * 0.6) return "#fdd835";
    return "#e53935";
  };

  // =============================================================
  return (
    <div style={S.page}>

      {/* ── HEADER ── */}
      <header style={S.header}>
        <div style={S.headerIcon}>🚗</div>
        <h1 style={S.headerTitle}>Vehicle Safety Prediction</h1>
        <p style={S.headerSub}>Real-time risk assessment from sensor data</p>
      </header>

      <main style={S.main}>

        {/* ══════════════════════════════
            LEFT: INPUT FORM
        ══════════════════════════════ */}
        <section style={S.card}>
          <h2 style={S.cardTitle}>Sensor Input</h2>

          {/* Sample loader */}
          <div style={S.sampleBox}>
            <p style={S.sampleHeading}>Quick Load Sample</p>
            <div style={S.sampleBtns}>
              {["safe", "warning", "danger"].map((t) => (
                <button key={t} onClick={() => loadSample(t)}
                  style={{ ...S.sampleBtn, background: THEME[t].bg, color: THEME[t].text, border: `1.5px solid ${THEME[t].border}` }}>
                  {THEME[t].emoji} {t.toUpperCase()}
                </button>
              ))}
            </div>
          </div>

          {/* Input fields */}
          <form onSubmit={handleSubmit}>
            {[
              { key: "distance",          label: "Distance to Object",    unit: "metres",  placeholder: "e.g. 15.4",  desc: "How far is the nearest object ahead?" },
              { key: "ttc",               label: "Time-to-Collision",     unit: "seconds", placeholder: "e.g. 1.8",   desc: "Estimated time before collision occurs" },
              { key: "relative_velocity", label: "Relative Velocity",     unit: "m/s",     placeholder: "e.g. -10",   desc: "Speed difference relative to the object" },
            ].map(({ key, label, unit, placeholder, desc }) => (
              <div key={key} style={S.fieldWrap}>
                <div style={S.fieldHeader}>
                  <label style={S.fieldLabel}>{label}</label>
                  <span style={S.fieldUnit}>{unit}</span>
                </div>
                <p style={S.fieldDesc}>{desc}</p>
                <input
                  type="number" step="any" name={key}
                  value={form[key]} onChange={handleChange}
                  placeholder={placeholder} style={S.input}
                />
              </div>
            ))}

            {error && <div style={S.errorBox}>⚠️ {error}</div>}

            <div style={S.btnRow}>
              <button type="submit" disabled={loading} style={S.btnPredict}>
                {loading ? "⏳  Analysing..." : "🔍  Predict Safety"}
              </button>
              <button type="button" onClick={handleReset} style={S.btnReset}>Reset</button>
            </div>
          </form>
        </section>

        {/* ══════════════════════════════
            RIGHT: RESULT + CHARTS
        ══════════════════════════════ */}
        <section style={S.card}>
          <h2 style={S.cardTitle}>Prediction Result</h2>

          {/* Placeholder */}
          {!result && !loading && (
            <div style={S.placeholder}>
              <div style={S.placeholderIcon}>📡</div>
              <p style={{ color: "#888", marginTop: 12 }}>
                Enter sensor values and click <strong>Predict Safety</strong> to see the analysis.
              </p>
              <p style={{ color: "#aaa", fontSize: 12, marginTop: 8 }}>
                Or use a Quick Load Sample to test the system instantly.
              </p>
            </div>
          )}

          {loading && (
            <div style={S.placeholder}>
              <div style={{ fontSize: 40 }}>⏳</div>
              <p style={{ color: "#888", marginTop: 12 }}>Analysing sensor data...</p>
            </div>
          )}

          {result && theme && submittedForm && (
            <>
              {/* ── Status Banner ── */}
              <div style={{ ...S.statusBanner, background: theme.bg, border: `2px solid ${theme.border}` }}>
                <div style={{ fontSize: 40 }}>{theme.emoji}</div>
                <div>
                  <div style={{ ...S.statusLabel, color: theme.accent }}>{theme.label}</div>
                  <div style={{ color: theme.text, fontSize: 13, marginTop: 2 }}>{result.message}</div>
                </div>
              </div>

              {/* ── Risk Meter ── */}
              <RiskMeter status={result.predicted_status} />

              {/* ── Arc Gauges ── */}
              <div style={S.chartsTitle}>Sensor Gauges</div>
              <div style={S.gaugeRow}>
                <ArcGauge
                  value={submittedForm.distance}
                  min={SENSOR_META.distance.min} max={SENSOR_META.distance.max}
                  color={gaugeColor("distance", submittedForm.distance)}
                  label="Distance" unit="m"
                />
                <ArcGauge
                  value={submittedForm.ttc}
                  min={SENSOR_META.ttc.min} max={SENSOR_META.ttc.max}
                  color={gaugeColor("ttc", submittedForm.ttc)}
                  label="TTC" unit="s"
                />
                <ArcGauge
                  value={Math.abs(submittedForm.relative_velocity)}
                  min={0} max={35}
                  color={gaugeColor("relative_velocity", submittedForm.relative_velocity)}
                  label="|Rel. Velocity|" unit="m/s"
                />
              </div>

              {/* ── Bar Gauges ── */}
              <div style={S.chartsTitle}>Sensor Breakdown</div>
              <BarGauge value={submittedForm.distance}          min={0}   max={120} color={gaugeColor("distance", submittedForm.distance)}                   label="Distance (m)"           unit="m"   />
              <BarGauge value={submittedForm.ttc}               min={0}   max={15}  color={gaugeColor("ttc", submittedForm.ttc)}                              label="Time-to-Collision (s)"  unit="s"   />
              <BarGauge value={Math.abs(submittedForm.relative_velocity)} min={0} max={35} color={gaugeColor("relative_velocity", submittedForm.relative_velocity)} label="Rel. Velocity (m/s)"    unit="m/s" />

              {/* ── Safe Thresholds Reference ── */}
              <div style={S.thresholdBox}>
                <div style={S.thresholdTitle}>Safe Zone Reference</div>
                <div style={S.thresholdGrid}>
                  {[
                    { label: "Distance",     safe: "> 40 m",  warn: "10–40 m",  danger: "< 10 m"   },
                    { label: "TTC",          safe: "> 5 s",   warn: "2–5 s",    danger: "< 2 s"    },
                    { label: "Rel. Vel.",    safe: "< 5 m/s", warn: "5–15 m/s", danger: "> 15 m/s" },
                  ].map(({ label, safe, warn, danger }) => (
                    <div key={label} style={S.thresholdRow}>
                      <span style={S.thresholdLabel}>{label}</span>
                      <span style={{ ...S.thresholdBadge, background: "#e8f5e9", color: "#2e7d32" }}>{safe}</span>
                      <span style={{ ...S.thresholdBadge, background: "#fffde7", color: "#7c5000" }}>{warn}</span>
                      <span style={{ ...S.thresholdBadge, background: "#ffebee", color: "#7f0000" }}>{danger}</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </section>
      </main>

      {/* ══════════════════════════════
          HISTORY SECTION
      ══════════════════════════════ */}
      <div style={S.historyWrap}>
        <button onClick={toggleHistory} style={S.histToggleBtn}>
          {showHistory ? "▲ Hide Prediction History" : "▼ Show Prediction History"}
        </button>

        {showHistory && (
          <div style={S.histCard}>
            <div style={S.histHeader}>
              <h3 style={{ margin: 0, color: "#1B2B4B" }}>Last 20 Predictions</h3>
              <button onClick={fetchHistory} style={S.btnReset}>🔄 Refresh</button>
            </div>
            {histLoading ? <p style={{ color: "#888" }}>Loading...</p>
            : history.length === 0 ? <p style={{ color: "#888" }}>No predictions yet.</p>
            : (
              <div style={{ overflowX: "auto" }}>
                <table style={S.histTable}>
                  <thead>
                    <tr style={{ background: "#1B2B4B", color: "#fff" }}>
                      {["#", "Distance", "TTC", "Rel. Vel.", "Status", "Time"].map(h => (
                        <th key={h} style={S.th}>{h}</th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {history.map((row, i) => {
                      const t = THEME[row.predicted_status] || THEME.safe;
                      return (
                        <tr key={row.id} style={{ background: i % 2 === 0 ? "#f9f9f9" : "#fff" }}>
                          <td style={S.td}>{row.id}</td>
                          <td style={S.td}>{row.distance.toFixed(1)} m</td>
                          <td style={S.td}>{row.ttc.toFixed(2)} s</td>
                          <td style={S.td}>{row.relative_velocity.toFixed(1)} m/s</td>
                          <td style={{ ...S.td }}>
                            <span style={{ background: t.bg, color: t.text, border: `1px solid ${t.border}`, padding: "2px 10px", borderRadius: 12, fontSize: 11, fontWeight: 700 }}>
                              {t.emoji} {row.predicted_status.toUpperCase()}
                            </span>
                          </td>
                          <td style={{ ...S.td, fontSize: 11, color: "#888" }}>{new Date(row.timestamp).toLocaleString()}</td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}
      </div>

      <footer style={S.footer}>
        Vehicle Safety Prediction System · FastAPI + React + SQLite · ML Project
      </footer>
    </div>
  );
}

